    (105, '[{"columnname":"Exploitation","datatype":"text","dvquerytext":"Select name as id, name as idval FROM exploitation WHERE expl_id > 0 ORDER BY name","isNullValue":"true","label":"Explotación:","layoutorder":1,"widgettype":"combo"},{"columnname":"Node type","datatype":"text","dvquerytext":"Select id as id, id as idval FROM cat_feature_node join cat_feature USING (id) WHERE id IS NOT NULL AND active ORDER BY id","isNullValue":"true","label":"Tipo de nodo:","layoutorder":2,"widgettype":"combo"}]')
